  "inlineSchema": "// This file defines all the tables in our database\n// Prisma reads this and creates the actual PostgreSQL tables\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ------- ENUMS (fixed list of allowed values) -------\n\n// The 3 user roles\nenum Role {\n  ADMIN\n  PM\n  DEVELOPER\n}\n\n// Task can be in one of these states\nenum TaskStatus {\n  TODO\n  IN_PROGRESS\n  IN_REVIEW\n  DONE\n  OVERDUE\n}\n\n// How important is the task\nenum Priority {\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\n// ------- TABLES -------\n\n// Users table - stores all users (admin, pm, developers)\nmodel User {\n  id        String   @id @default(uuid())\n  name      String\n  email     String   @unique\n  password  String // will be hashed, never stored as plain text\n  role      Role     @default(DEVELOPER)\n  createdAt DateTime @default(now())\n\n  // One user can manage many projects (if they are a PM)\n  managedProjects Project[] @relation(\"PMProjects\")\n\n  // One user can be assigned many tasks (if they are a Developer)\n  assignedTasks Task[] @relation(\"AssignedTasks\")\n\n  // One user can have many activity log entries\n  activityLogs ActivityLog[]\n\n  // One user can have many notifications\n  notifications Notification[]\n\n  // One user can have many refresh tokens\n  refreshTokens RefreshToken[]\n}\n\n// Clients table - the company's clients (customers)\nmodel Client {\n  id        String   @id @default(uuid())\n  name      String\n  email     String   @unique\n  createdAt DateTime @default(now())\n\n  // One client can have many projects\n  projects Project[]\n}\n\n// Projects table\nmodel Project {\n  id          String   @id @default(uuid())\n  name        String\n  description String? // ? means optional\n  createdAt   DateTime @default(now())\n\n  // Which client this project belongs to\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id])\n\n  // Which PM manages this project\n  pmId String\n  pm   User   @relation(\"PMProjects\", fields: [pmId], references: [id])\n\n  // One project has many tasks\n  tasks Task[]\n\n  // One project has many activity logs\n  activityLogs ActivityLog[]\n\n  // Index on pmId because we often search \"all projects for this PM\"\n  @@index([pmId])\n}\n\n// Tasks table\nmodel Task {\n  id          String     @id @default(uuid())\n  title       String\n  description String?\n  status      TaskStatus @default(TODO)\n  priority    Priority   @default(MEDIUM)\n  dueDate     DateTime?\n  isOverdue   Boolean    @default(false)\n  createdAt   DateTime   @default(now())\n\n  // Which project this task belongs to\n  projectId String\n  project   Project @relation(fields: [projectId], references: [id])\n\n  // Which developer is assigned to this task (optional)\n  assignedToId String?\n  assignedTo   User?   @relation(\"AssignedTasks\", fields: [assignedToId], references: [id])\n\n  // Each task has an activity log (history of changes)\n  activityLogs ActivityLog[]\n\n  // Indexes: we often filter tasks by these columns\n  @@index([projectId])\n  @@index([assignedToId])\n  @@index([status])\n}\n\n// ActivityLog table - records every status change on tasks\nmodel ActivityLog {\n  id          String   @id @default(uuid())\n  description String // e.g. \"Ravi moved Task #12 from In Progress → In Review\"\n  createdAt   DateTime @default(now())\n\n  // Who made the change\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  // Which task was changed\n  taskId String\n  task   Task   @relation(fields: [taskId], references: [id])\n\n  // Which project (stored here so we can filter by project easily)\n  projectId String\n  project   Project @relation(fields: [projectId], references: [id])\n\n  // Indexes for fast filtering\n  @@index([projectId])\n  @@index([userId])\n  @@index([taskId])\n}\n\n// Notifications table - in-app alerts for users\nmodel Notification {\n  id        String   @id @default(uuid())\n  message   String\n  isRead    Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  // Which user gets this notification\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  @@index([userId])\n}\n\n// RefreshToken table - stores JWT refresh tokens\nmodel RefreshToken {\n  id        String   @id @default(uuid())\n  token     String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  // Which user this token belongs to\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  @@index([userId])\n}\n",
